import{_ as a,o as t,c as i,ag as o}from"./chunks/framework.ByAj6Cie.js";const u=JSON.parse('{"title":"Motor Nameplates","description":"","frontmatter":{},"headers":[],"relativePath":"es/industrial-equipment/motors/motor-nameplates.md","filePath":"es/industrial-equipment/motors/motor-nameplates.md"}'),r={name:"es/industrial-equipment/motors/motor-nameplates.md"};function n(l,e,s,c,p,d){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="motor-nameplates" tabindex="-1">Motor Nameplates <a class="header-anchor" href="#motor-nameplates" aria-label="Permalink to &quot;Motor Nameplates&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Motor nameplates provide essential technical information about a motor’s electrical and mechanical characteristics.</p><p>They contain standardized data required for installation, operation, protection, and maintenance.</p><p>Understanding nameplate information is critical for selecting, connecting, and operating motors correctly.</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>The purpose of motor nameplates is to:</p><ul><li>Define the operating limits of the motor</li><li>Provide key electrical and performance data</li><li>Ensure proper installation and connection</li><li>Support correct selection of protection and control devices</li></ul><p>Nameplates act as the primary reference for motor specifications.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>The nameplate is attached to the motor housing and includes rated values determined by the manufacturer.</p><p>These values define the conditions under which the motor is designed to operate safely and efficiently.</p><p>Common information includes:</p><ul><li>Rated voltage and frequency</li><li>Full load current</li><li>Power rating</li><li>Speed</li><li>Power factor and efficiency</li><li>Insulation class and temperature limits</li></ul><p>This data is used to configure the electrical system and verify compatibility with the application.</p><h2 id="applications" tabindex="-1">Applications <a class="header-anchor" href="#applications" aria-label="Permalink to &quot;Applications&quot;">​</a></h2><p>Motor nameplates are used in:</p><ul><li>Installation and commissioning of motors</li><li>Selection of cables, breakers, and protection devices</li><li>Setting up drives and control systems</li><li>Maintenance and troubleshooting</li><li>Verification of motor performance</li></ul><p>They are essential throughout the motor lifecycle.</p><h2 id="key-parameters" tabindex="-1">Key Parameters <a class="header-anchor" href="#key-parameters" aria-label="Permalink to &quot;Key Parameters&quot;">​</a></h2><ul><li><p><strong>Voltage and frequency</strong><br> Must match the power supply</p></li><li><p><strong>Current rating</strong><br> Used for sizing protection and conductors</p></li><li><p><strong>Power rating</strong><br> Indicates mechanical output capability</p></li><li><p><strong>Speed</strong><br> Defines operating characteristics under load</p></li><li><p><strong>Efficiency</strong><br> Indicates energy performance</p></li><li><p><strong>Service factor</strong><br> Defines allowable overload capacity under specific conditions</p></li><li><p><strong>Insulation class</strong><br> Determines thermal limits and durability</p></li></ul><h2 id="practical-notes" tabindex="-1">Practical Notes <a class="header-anchor" href="#practical-notes" aria-label="Permalink to &quot;Practical Notes&quot;">​</a></h2><ul><li>Always verify nameplate data before connecting a motor</li><li>Incorrect voltage or frequency can cause immediate damage</li><li>Protection devices must be set based on nameplate current</li><li>Service factor should not be used for continuous overload operation</li><li>Nameplate data represents rated conditions, not all possible operating scenarios</li></ul>',23)])])}const h=a(r,[["render",n]]);export{u as __pageData,h as default};
